function GameCard({
  image,
  fallbackBg,
  isMobile,
}: {
  image: string;
  fallbackBg: string;
  isMobile: boolean;
}) {
  return (
    <div
      style={{
        position: "relative",
        width: isMobile ? "120px" : "155px",
        height: isMobile ? "165px" : "200px",
        borderRadius: "12px",
        overflow: "hidden",
        flexShrink: 0,
        cursor: "pointer",
        background: fallbackBg,
      }}
    >
      <img
        src={image}
        style={{
          width: "100%",
          height: "100%",
          objectFit: "cover",
          display: "block",
        }}
        onError={(e) => {
          (e.target as HTMLImageElement).style.display = "none";
        }}
      />
    </div>
  );
}

